pub proof fn lemma_strength_combine(
    s: Seq<i32>,
    left: Seq<i32>,
    right: Seq<i32>,
    mid: int,
    m_left: int,
    p_left: int,
    s_left: int,
    t_left: int,
    m_right: int,
    p_right: int,
    s_right: int,
    t_right: int,
)
    requires
        s.len() > 1,
        0 < mid < s.len() as int,
        left.len() == mid,
