    match tree.expose_with_priority() {
        | None => (ParamTreap::new(), false, ParamTreap::new()),
        | Some((left, root_key, priority, right)) => match key.cmp(&root_key) {
            | Less => {
                let (ll, found, lr) = split_inner(&left, key);
