fn get_neighbors<V: StT + Hash + Ord>(graph: &LabUnDirGraphStEph<V, WrappedF64>, v: &V) -> SetStEph<V> {
    let mut neighbors = SetLit![];
    for edge in graph.labeled_edges().iter() {
